def handle_password_dialogs\(\):
    """循环检测并处理密码弹窗,直到没有弹窗为止"""
    print\("→ 检测密码弹窗..."\)
    time.sleep\(2\)  # 等待弹窗可能出现

    attempt = 0
    while True:
        attempt += 1
        print\(f"   第 {attempt} 次检测..."\)

        if check_password_dialog\(\):
            print\(f"   ⚠️ 检测到密码弹窗"\)
            click_password_cancel\(\)
            time.sleep\(2\)  # 等待弹窗关闭
        else:
            print\("   ✅ 未检测到密码弹窗"\)
            break

def load_qr_coordinates\(\):
    """从文件加载二维码坐标"""
    if not os.path.exists\(QR_COORD_FILE\):
        return None
    try:
        with open\(QR_COORD_FILE\) as f:
            x1, y1, x2, y2 = map\(int, f.readline\(\).strip\(\).split\(","\)\)
        print\(f"✓ 已加载二维码坐标: \({x1},{y1}\) -> \({x2},{y2}\)"\)
        return \(x1, y1, x2, y2\)
    except Exception as e:
        print\(f"  加载二维码坐标失败: {e}"\)
        return None

def capture_and_send_qr\(qr_bbox\):
    """截取二维码并发送到企业微信"""
    try:
        x1, y1, x2, y2 = qr_bbox
        img = ImageGrab.grab\(bbox=\(x1, y1, x2, y2\)\)
    except Exception as e:
        print\(f"   截图失败: {e}"\)
        return False

    buf = io.BytesIO\(\)
    img.save\(buf, format="PNG"\)
    raw = buf.getvalue\(\)
    b64 = base64.b64encode\(raw\).decode\("utf-8"\)
    md5 = hashlib.md5\(raw\).hexdigest\(\)

    headers = {"Content-Type": "application/json"}
    text_payload = {
        "msgtype": "text",
        "text": {
            "content": \(
                f"WPS 需要重新登录\\n"
                f"请用微信扫描下方二维码\\n"
                f"时间: {time.strftime\('%Y-%m-%d %H:%M:%S'\)}"
            \)
        }
    }
    image_payload = {
        "msgtype": "image",
        "image": {"base64": b64, "md5": md5}
    }

    for payload in \(text_payload, image_payload\):
        try:
            resp = requests.post\(
                WXWORK_WEBHOOK_URL,
                data=json.dumps\(payload, ensure_ascii=False\).encode\("utf-8"\),
                headers=headers,
                timeout=15,
            \)
            result = resp.json\(\)
            if result.get\("errcode"\) != 0:
                print\(f"   企业微信返回错误: {result}"\)
                return False
        except Exception as e:
            print\(f"   发送失败: {e}"\)
            return False

    return True

